// ── Module-level memory fallback ─────────────────────────
const _memStore = {};
let _storageWorks = null;

async function testStorage(){
  if(_storageWorks !== null) return _storageWorks;
  try{
    if(typeof window.storage === 'undefined'){
      _storageWorks=false; return false;
    }
    const r = await window.storage.set("kouno_test", "ok");
    if(!r){ _storageWorks=false; return false; }
    const g = await window.storage.get("kouno_test");
    _storageWorks = g?.value==="ok";
    return _storageWorks;
  }catch(e){
    console.warn("Storage unavailable:", e.message);
    _storageWorks=false;
    return false;
  }
}

async function storageSave(key, value) {
  _memStore[key] = value;
  try {
    const works = await testStorage();
    if(!works) return false;
    const result = await window.storage.set(key, value);
    if(!result){ console.warn("storage.set returned null for key:", key); return false; }
    return true;
  } catch(e) {
    console.warn("storageSave error:", e.message);
    return false;
  }
}
async function storageLoad(key) {
  try {
    const works = await testStorage();
    if(works){
      const res = await window.storage.get(key);
      if(res?.value){
        _memStore[key] = res.value;
        return res.value;
      }
    }
  } catch(_) {}
  return _memStore[key] || null;
}

