const rollRar=()=>{const r=Math.random()*100;if(r<2)return"legendary";if(r<8)return"epic";if(r<20)return"rare";if(r<45)return"uncommon";return"common";};

// Legendary special effects pool
const LEG_FX=[
  {id:"lx1",label:"⚡ クリティカル率+25%", crit:0.25},
  {id:"lx2",label:"🩸 HP吸収(ダメ10%)",   drain:0.1},
  {id:"lx3",label:"🔮 魔法ダメ+40%",       magBoost:0.4},
  {id:"lx4",label:"🛡️ 被ダメ-20%",         dmgReduce:0.2},
  {id:"lx5",label:"⚔️ 追加攻撃+1",          extraHit:true},
  {id:"lx6",label:"🌟 全ステ+15",           allStat:15},
];

// Apply rarity multiplier to base stats, add legendary effect
function applyRarity(item, rar){
  const mul=RARITY[rar].mul;
  const scaled={
    ...item, rar,
    uid: Date.now()+Math.random(),
    atk: Math.round((item.atk||0)*mul),
    def: Math.round((item.def||0)*mul),
    spd: Math.round((item.spd||0)*mul),
  };
  if(rar==="legendary") scaled.fx=LEG_FX[Math.floor(Math.random()*LEG_FX.length)];
  return scaled;
}

