function getDropPool(dlv){
  const t=Math.min(6,Math.ceil(dlv/1.5));
  return[...WEAPONS.filter(w=>w.tier<=t),...ARMORS.filter(a=>a.tier<=t),...ACCS.filter(c=>c.tier<=t),...CONS];
}

