// ── Character Portraits v4 (exact crop, no clipping) ─────────
const PORTRAITS={
  miria_bound:{
    normal:"data:image/png;base64,",
    smile:"data:image/png;base64,",
    anxious:"data:image/png;base64,",
    silent:"data:image/png;base64,",
    sad:"data:image/png;base64,",
    surprise:"data:image/png;base64,",
  },
  miria_free:{
    normal:"data:image/png;base64,",
    happy:"data:image/png;base64,",
    bashful:"data:image/png;base64,",
    sad:"data:image/png;base64,",
    crying:"data:image/png;base64,",
    determined:"data:image/png;base64,",
  },
  idea:{
    normal:"data:image/png;base64,",
    cold:"data:image/png;base64,",
    angry:"data:image/png;base64,",
    confused:"data:image/png;base64,",
    conflicted:"data:image/png;base64,",
    determined:"data:image/png;base64,",
  },
  demon_king:{
    normal:"data:image/png;base64,",
    cruel:"data:image/png;base64,",
    angry:"data:image/png;base64,",
    sneer:"data:image/png;base64,",
    sad:"data:image/png;base64,",
    serene:"data:image/png;base64,",
  },
};

function Portrait({char, expr, size=88}){
  const exprs=PORTRAITS[char];
  if(!exprs) return null;
  const src=exprs[expr]||exprs.normal;
  if(!src) return null;
  // Display as portrait (taller than wide) for full face visibility
  const w=size;
  const h=Math.round(size*1.3); // 縦長でフル表示
  return(
    <div style={{
      width:w,height:h,flexShrink:0,
      borderRadius:4,overflow:"hidden",
      border:"1px solid rgba(200,169,110,.3)",
      boxShadow:"0 2px 8px rgba(0,0,0,.5)",
    }}>
      <img src={src} alt="" style={{
        width:"100%",height:"100%",
        objectFit:"cover",objectPosition:"center top",
        display:"block",
      }} onError={e=>{e.target.parentElement.style.display="none";}}/>
    </div>
  );
}

function getPortrait(speaker, floorId, text){
  if(!speaker) return null;
  let char=null;
  if(speaker.includes("ミリア")) char=(floorId&&floorId<=5)?"miria_bound":"miria_free";
  else if(speaker.includes("イデア")) char="idea";
  else if(speaker.includes("魔王")||speaker.includes("ラグナ初代")) char="demon_king";
  if(!char) return null;
  const expr=detectExpression(speaker,text);
  const key=exprToPortrait(char,expr);
  return {char, expr:key};
}

// Detect expression from speaker name hints + dialogue text
function detectExpression(speaker,text){
  const s=speaker||"",t=text||"";
  if(s.includes("泣き")||s.includes("泣く")) return "crying";
  if(s.includes("笑って")||s.includes("笑う")||s.includes("微笑")) return "smile_or_happy";
  if(s.includes("照れ")) return "bashful";
  if(s.includes("決意")||s.includes("決然")) return "determined";
  if(s.includes("震え")||s.includes("怯え")||s.includes("警告音")) return "anxious";
  if(s.includes("静かに")||s.includes("沈黙")||s.includes("小声")||s.includes("ポツリ")) return "silent";
  if(s.includes("苦しそう")||s.includes("葛藤")) return "conflicted";
  if(s.includes("怒")||s.includes("激怒")) return "angry";
  if(s.includes("冷淡")||s.includes("無表情")) return "cold";
  const sad   =["ごめん","申し訳","消えた","死","泣","悲し","後悔","捨て","ひど","切れ","痛","辛い","失","ダメ","嫌だった","すまない"];
  const happy =["ありがとう","よかった","嬉し","楽し","笑","好き","綺麗","一緒","帰","出よう","行こう","うん","おかえり"];
  const angry =["許さ","ふざけ","バカ","道具だ","命令に従え","黙れ","うるさ","邪魔","お前は道具"];
  const anxious=["急いで","早く","——","危ない","警告","止まれ","逃げ","来た","間に合","注意","！！","くる"];
  const silent =["……","知らない","わからない","黙","沈黙","そうか","そうだ"];
  const det   =["任せて","行きます","絶対","必ず","やり遂","戦う","諦めない","命令拒否","消す","起動","解放","証明"];
  const surp  =["え？","まさか","どうして","——っ","！？","信じられ","本当に？","嘘だろ"];
  const sneer =["ふふ","くく","笑止","愚か","証明してみせろ","手の中","我々の","計算通り","見せてみろ"];
  const conf  =["どうすれば","なぜだろ","どちら","正しいのか","迷","悩","わからなく"];
  const cold  =["訓練完了","命令を","排除","効率","処理","最適解","計算","データ","次の命令"];
  const score=(arr)=>arr.filter(k=>t.includes(k)).length;
  const scores={sad:score(sad),happy:score(happy),angry:score(angry),anxious:score(anxious),
    silent:score(silent),determined:score(det),surprise:score(surp),
    sneer:score(sneer),conflicted:score(conf),cold:score(cold)};
  const top=Object.entries(scores).sort((a,b)=>b[1]-a[1])[0];
  return top[1]>0?top[0]:"normal";
}

function exprToPortrait(char,expr){
  const maps={
    miria_bound:{normal:"normal",smile:"smile",smile_or_happy:"smile",anxious:"anxious",
      silent:"silent",sad:"sad",surprise:"surprise",happy:"smile",determined:"anxious",
      crying:"sad",conflicted:"silent",angry:"anxious",cold:"silent",bashful:"smile"},
    miria_free:{normal:"normal",happy:"happy",smile_or_happy:"happy",smile:"happy",
      bashful:"bashful",sad:"sad",crying:"crying",determined:"determined",
      anxious:"sad",silent:"normal",surprise:"happy",conflicted:"sad",
      angry:"determined",cold:"normal"},
    idea:{normal:"normal",cold:"cold",angry:"angry",confused:"confused",
      conflicted:"conflicted",determined:"determined",smile_or_happy:"normal",
      anxious:"conflicted",silent:"cold",sad:"confused",surprise:"confused",
      happy:"normal",bashful:"confused",sneer:"cold",serene:"normal",smile:"normal"},
    demon_king:{normal:"normal",cruel:"cruel",cold:"cruel",angry:"angry",
      sneer:"sneer",sad:"sad",serene:"serene",determined:"cruel",
      conflicted:"sad",silent:"serene",smile_or_happy:"sneer",
      anxious:"angry",surprise:"angry",happy:"sneer",bashful:"normal"},
  };
  return maps[char]?.[expr]||"normal";
}

// uid-based lookup: eq stores uid, find item by uid in inventory
function calcStatsWithInv(base,eq,inv){
  const find=uid=>inv.find(i=>i.uid===uid);
  const w=find(eq.weapon),a=find(eq.armor),c=find(eq.acc);
  const all15=(i)=>i?.fx?.allStat||0;
  return{
    atk:base.atk+(w?.atk||0)+(a?.atk||0)+(c?.atk||0)+all15(w)+all15(a)+all15(c),
    def:base.def+(w?.def||0)+(a?.def||0)+(c?.def||0)+all15(w)+all15(a)+all15(c),
    spd:base.spd+(w?.spd||0)+(a?.spd||0)+(c?.spd||0)+all15(w)+all15(a)+all15(c),
  };
}

