function generateShop(playerLv){
  const tier=Math.min(6,Math.ceil(playerLv/8)+1);
  const equipPool=[...WEAPONS,...ARMORS,...ACCS].filter(e=>e.tier<=tier);
  const shopEquip=[];
  const usedBases=new Set();
  const rShop=()=>{const r=Math.random()*100;if(r<1)return"legendary";if(r<5)return"epic";if(r<20)return"rare";if(r<50)return"uncommon";return"common";};
  let attempts=0;
  while(shopEquip.length<3&&attempts<30){
    attempts++;
    if(equipPool.length===0) break;
    const base=equipPool[Math.floor(Math.random()*equipPool.length)];
    if(usedBases.has(base.id)) continue;
    usedBases.add(base.id);
    const rar=rShop();
    const item=applyRarity(base,rar);
    item.price=Math.max(50,Math.floor(RARITY[rar].sell*3.5+50));
    item.uid="shop_"+Date.now()+Math.random();
    shopEquip.push(item);
  }
  const cons=[...SHOP_CONSUMABLES,...SHOP_STAT_BOOSTS];
  const picks=[];
  let tries=0;
  while(picks.length<2&&tries<20){
    tries++;
    const c=cons[Math.floor(Math.random()*cons.length)];
    if(!picks.find(p=>p.id===c.id)) picks.push({...c,uid:"shop_"+Date.now()+Math.random()});
  }
  return[...shopEquip,...picks];
}

