function genGuestId(){
  return "guest_"+Math.random().toString(36).slice(2,10);
}
async function getOrCreateGuestId(){
  const KEY="kouno_guest_id";
  const existing = await storageLoad(KEY);
  if(existing) return existing;
  const id="guest_"+Math.random().toString(36).slice(2,10);
  await storageSave(KEY, id);
  return id;
}

