// ── Story Screen ─────────────────────────────────────────
function StoryScreen({floorId, onNext}){
  const ev = SE[floorId];
  const[page,setPage] = useState(0);
  const[showLog,setShowLog] = useState(false);
  const isMajor = !!(ev && ev.major);
  // pages配列があればそれを使い、なければd/dlから1ページ生成
  const pages = ev.pages || [{d:ev.d, dl:ev.dl}];
  const cur = pages[page] || pages[0];
  const isLast = page >= pages.length - 1;

  function advance(){
    if(!isLast){ setPage(p=>p+1); setShowLog(false); }
    else onNext();
  }

  return(
    <div style={{
      position:"fixed",inset:0,zIndex:60,
      background:isMajor
        ? "radial-gradient(ellipse at 50% 20%, rgba(200,80,80,.15) 0%, rgba(6,8,12,.98) 70%)"
        : "#06080c",
      display:"flex",flexDirection:"column",
      fontFamily:"'Courier New',monospace",color:"#c8b890",
      animation:"fadeIn .5s ease",
    }} onClick={advance}>
      {/* Header */}
      <div style={{padding:"14px 16px 10px",borderBottom:"1px solid #2a2010"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
          <div>
            <div style={{fontSize:9,color:"#6a5a3a",letterSpacing:".15em",marginBottom:3}}>
              {ev.p} ／ 第{floorId}層クリア
            </div>
            <div style={{
              fontSize:isMajor?14:12,fontWeight:700,
              color:isMajor?"#ff8060":"#e8d090",letterSpacing:".06em",
              textShadow:isMajor?"0 0 20px #ff806060":"none",
            }}>{ev.t}</div>
          </div>
          <div style={{display:"flex",gap:6,alignItems:"center"}}>
            {pages.length>1&&(
              <span style={{fontSize:8,color:"#4a3a1a"}}>{page+1}/{pages.length}</span>
            )}
            <button onClick={e=>{e.stopPropagation();onNext();}} style={{
              background:"none",border:"1px solid #3a2a0a",color:"#6a5a3a",
              padding:"3px 8px",cursor:"pointer",fontSize:8,
              fontFamily:"inherit",borderRadius:2,
            }}>SKIP</button>
          </div>
        </div>
      </div>

      {/* Page dots */}
      {pages.length>1&&(
        <div style={{display:"flex",justifyContent:"center",gap:5,padding:"6px 0 2px"}}>
          {pages.map((_,i)=>(
            <div key={i} style={{
              width:i===page?14:6,height:6,borderRadius:3,
              background:i===page?"#c8a96e":i<page?"#5a4a2a":"#2a2010",
              transition:"all .3s",
            }}/>
          ))}
        </div>
      )}

      {/* Body - scrollable */}
      <div style={{flex:1,overflowY:"auto",padding:"12px 16px"}} onClick={e=>e.stopPropagation()}>
        {isMajor&&page===0&&(
          <div style={{fontSize:9,color:"#ff8060",letterSpacing:".2em",marginBottom:10}}>
            ── MAJOR EVENT ──
          </div>
        )}

        {cur.d&&(
          <div style={{fontSize:11,lineHeight:1.9,color:"#b0a080",marginBottom:14,whiteSpace:"pre-wrap"}}>
            {cur.d}
          </div>
        )}

        {cur.dl&&cur.dl.map((d,i)=>{
          const portraitData=getPortrait(d.s, floorId, d.l);
          const isMiria=d.s&&d.s.includes("ミリア");
          const isIdea=d.s&&d.s.includes("イデア");
          const isDemon=d.s&&(d.s.includes("魔王")||d.s.includes("ラグナ"));
          const hasPortrait=!!portraitData;
          const nameColor=isMiria?"#40c0b0":isIdea?"#80a0ff":isDemon?"#ff6060":
                          d.s==="主人公"?"#c8a96e":i%2===0?"#c8a96e":"#a080ff";
          const bgColor=isMiria?"rgba(64,200,200,.07)":isIdea?"rgba(80,120,255,.07)":
                        isDemon?"rgba(200,60,60,.08)":
                        d.s==="主人公"?"rgba(200,169,110,.07)":
                        i%2===0?"rgba(200,169,110,.05)":"rgba(100,80,200,.05)";
          const bdColor=isMiria?"#40c0c030":isIdea?"#6080ff25":isDemon?"#ff404030":
                        d.s==="主人公"?"#c8a96e25":i%2===0?"#c8a96e18":"#8060ff18";
          return(
            <div key={i} style={{
              marginBottom:10,padding:hasPortrait?"8px 10px":"8px 12px",
              background:bgColor,border:`1px solid ${bdColor}`,
              borderRadius:3,animation:`slideUp .3s ease ${i*.1}s both`,
              display:"flex",alignItems:"flex-start",gap:hasPortrait?10:0,
            }}>
              {portraitData&&(
                <Portrait char={portraitData.char} expr={portraitData.expr} size={88}/>
              )}
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontSize:9,marginBottom:3,letterSpacing:".08em",color:nameColor,fontWeight:700}}>
                  {d.s}
                </div>
                <div style={{fontSize:11,color:"#d0c090",lineHeight:1.7,wordBreak:"break-all"}}>
                  「{d.l}」
                </div>
              </div>
            </div>
          );
        })}

        {cur.log&&cur.log.length>0&&(
          <div style={{marginBottom:8}}>
            <button onClick={e=>{e.stopPropagation();setShowLog(s=>!s);}} style={{
              background:"none",border:"1px solid #2a3a2a",color:"#3a6a3a",
              padding:"3px 9px",cursor:"pointer",fontSize:8,
              fontFamily:"inherit",borderRadius:2,marginBottom:showLog?6:0,
            }}>{showLog?"▼":"▶"} システムログ</button>
            {showLog&&cur.log.map((l,i)=>(
              <div key={i} style={{fontSize:9,color:"#3a6a3a",lineHeight:1.8,paddingLeft:4}}>{l}</div>
            ))}
          </div>
        )}
      </div>

      {/* Footer tap hint */}
      <div style={{padding:"10px 16px",borderTop:"1px solid #1a1808",
        display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div style={{fontSize:8,color:"#3a2a0a"}}>
          {isLast?"画面タップで閉じる":"画面タップで次のページ"}
        </div>
        <button onClick={e=>{e.stopPropagation();advance();}} style={{
          background:ev.ending&&isLast
            ?"linear-gradient(135deg,rgba(255,192,64,.2),rgba(255,192,64,.08))"
            :"linear-gradient(135deg,rgba(200,169,110,.12),rgba(200,169,110,.04))",
          border:`1px solid ${ev.ending&&isLast?"#ffc04050":"#c8a96e30"}`,
          color:ev.ending&&isLast?"#ffc040":"#c8a96e",
          padding:"8px 16px",cursor:"pointer",
          fontSize:ev.ending&&isLast?12:10,fontWeight:ev.ending&&isLast?700:400,
          letterSpacing:".1em",fontFamily:"inherit",borderRadius:2,
        }}>
          {ev.ending&&isLast?"✦ エンディング ✦":isLast?"▶ 次へ":"次ページ ▶"}
        </button>
      </div>
    </div>
  );
}

// ── Result Screen ─────────────────────────────────────────
function ResultOverlay({hp,rank,newSpells,newPassives,legDrop,drops,dungeonName,dungeonIcon,gold,lv,onDone}){
  const won=hp>0;
  const hasSkills=newSpells.length>0||newPassives.length>0;
  const[phase,setPhase]=useState(0);

  useEffect(()=>{
    // Phase progression only (no auto-close)
    const t1=setTimeout(()=>setPhase(1), 400);
    const t2=setTimeout(()=>setPhase(2), 1200);
    const t3=setTimeout(()=>setPhase(3), 2200);
    return()=>{[t1,t2,t3].forEach(clearTimeout);};
  },[]);

  return(
    <div style={{
      position:"fixed",inset:0,zIndex:50,
      background: won
        ? "radial-gradient(ellipse at 50% 30%, rgba(200,169,110,.18) 0%, rgba(6,8,12,.97) 60%)"
        : "radial-gradient(ellipse at 50% 30%, rgba(255,80,64,.12) 0%, rgba(6,8,12,.97) 60%)",
      display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",
      fontFamily:"'Courier New',monospace",
      animation:"fadeIn .4s ease",
      overflow:"hidden",
      cursor:"pointer",
    }} onClick={onDone}>
      {/* Particles on clear */}
      {won && phase>=1 && ["✦","✦","✧","✦","✦","✧","✦"].map((c,i)=>(
        <div key={i} style={{
          position:"absolute",
          left:`${10+i*13}%`, top:"30%",
          fontSize:14, color:["#ffc040","#c8a96e","#ffffff","#40c880"][i%4],
          animation:`particle ${1+i*.2}s ease ${i*.15}s forwards`,
          pointerEvents:"none",
        }}>{c}</div>
      ))}

      {/* Main card */}
      <div style={{
        maxWidth:340,width:"92%",
        animation:"slideUp .5s ease",
      }}>

        {/* Dungeon name */}
        <div style={{textAlign:"center",marginBottom:14,animation:"fadeIn .6s ease .2s both"}}>
          <div style={{fontSize:11,color:"#6a5a3a",letterSpacing:".15em",marginBottom:4}}>
            {dungeonIcon} {dungeonName}
          </div>
        </div>

        {/* Clear / Fail title */}
        <div style={{
          textAlign:"center",marginBottom:16,
          animation:"zoomIn .5s cubic-bezier(.17,.67,.31,1.4) .3s both",
        }}>
          {won ? (
            <div>
              <div style={{fontSize:36,marginBottom:4,filter:"drop-shadow(0 0 16px #ffc040)"}}>🏆</div>
              <div style={{
                fontSize:24,fontWeight:900,color:"#ffc040",letterSpacing:".2em",
                textShadow:"0 0 30px #ffc040a0, 0 0 60px #ffc04040",
              }}>CLEAR!</div>
            </div>
          ) : (
            <div>
              <div style={{fontSize:36,marginBottom:4}}>💀</div>
              <div style={{fontSize:22,fontWeight:700,color:"#ff5040",letterSpacing:".15em",
                textShadow:"0 0 20px #ff504060"}}>GAME OVER</div>
            </div>
          )}
        </div>

        {/* Rank */}
        {rank && phase>=1 && (
          <div style={{
            display:"flex",alignItems:"center",justifyContent:"center",gap:12,
            marginBottom:16,
            animation:"rankBounce .6s cubic-bezier(.17,.67,.31,1.4) both",
          }}>
            <div style={{
              fontSize:52,fontWeight:900,color:rank.c,
              textShadow:`0 0 24px ${rank.c}, 0 0 48px ${rank.c}60`,
              letterSpacing:".05em",lineHeight:1,
            }}>
              {rank.r}
            </div>
            <div style={{textAlign:"left"}}>
              <div style={{fontSize:9,color:"#6a5a3a",letterSpacing:".15em"}}>RANK</div>
              <div style={{fontSize:10,color:"#c8a870",marginTop:2}}>
                {rank.r==="S"?"完璧な攻略！":rank.r==="A"?"素晴らしい！":rank.r==="B"?"まずまず":rank.r==="C"?"なんとか":rank.r==="D"?"ギリギリ…":""}
              </div>
            </div>
          </div>
        )}

        {/* Stats row */}
        {phase>=2 && (
          <div style={{
            display:"flex",gap:6,justifyContent:"center",marginBottom:14,
            animation:"slideUp .4s ease both",
          }}>
            {[
              ["Lv",lv,"#c8a96e"],
              ["💰",gold+"G","#ffc040"],
              ["ドロップ",drops.length+"個","#40c880"],
            ].map(([l,v,c])=>(
              <div key={l} style={{
                background:"rgba(255,255,255,.04)",border:"1px solid rgba(255,255,255,.08)",
                borderRadius:3,padding:"6px 10px",textAlign:"center",flex:1,
              }}>
                <div style={{fontSize:8,color:"#6a5a3a",marginBottom:2}}>{l}</div>
                <div style={{fontSize:11,color:c,fontWeight:700}}>{v}</div>
              </div>
            ))}
          </div>
        )}

        {/* Legendary drop */}
        {legDrop && phase>=2 && (
          <div style={{
            background:"linear-gradient(135deg,rgba(255,192,64,.18),rgba(255,192,64,.05))",
            border:"2px solid #ffc04070",borderRadius:3,padding:12,marginBottom:12,
            textAlign:"center",animation:"lgBig 1.5s infinite, slideUp .4s ease both",
          }}>
            <div style={{fontSize:8,color:"#ffc040",letterSpacing:".25em",marginBottom:6,animation:"shimmer 1.5s infinite"}}>
              ✦ LEGENDARY DROP ✦
            </div>
            <div style={{fontSize:32,marginBottom:4,filter:"drop-shadow(0 0 12px #ffc040)"}}>{legDrop.icon||"⚔️"}</div>
            <div style={{fontSize:14,color:"#ffc040",fontWeight:700,textShadow:"0 0 12px #ffc040"}}>{legDrop.name}</div>
            {legDrop.fx&&<div style={{fontSize:8,color:"#ffdc80",marginTop:3}}>{legDrop.fx.label}</div>}
          </div>
        )}

        {/* Drop list (non-legendary) */}
        {drops.length>0 && phase>=2 && (
          <div style={{
            display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:5,marginBottom:12,
            animation:"slideUp .5s ease .1s both",
          }}>
            {drops.filter(d=>d.rar!=="legendary").slice(0,8).map((item,i)=>(
              <div key={i} style={{
                background:"rgba(10,8,6,.8)",
                border:`1px solid ${RARITY[item.rar||"common"].color}40`,
                borderRadius:2,padding:5,textAlign:"center",
                animation:`slideUp .3s ease ${i*.06}s both`,
              }}>
                <div style={{fontSize:14}}>{item.icon||"⚔️"}</div>
                <div style={{fontSize:6,color:RARITY[item.rar||"common"].color,marginTop:1,lineHeight:1.3}}>{item.name}</div>
              </div>
            ))}
          </div>
        )}

        {/* New skills */}
        {hasSkills && phase>=3 && (
          <div style={{
            background:"rgba(80,60,200,.08)",border:"1px solid #8060ff30",
            borderRadius:2,padding:10,marginBottom:12,
            animation:"slideUp .4s ease both",
          }}>
            <div style={{fontSize:8,color:"#c060ff",letterSpacing:".12em",marginBottom:6}}>✨ 新スキル習得！</div>
            {newSpells.map(s=>(<div key={s.id} style={{display:"flex",alignItems:"center",gap:6,marginBottom:4}}><span style={{fontSize:14}}>{s.icon}</span><span style={{fontSize:9,color:"#c080ff",fontWeight:700}}>{s.name}</span><span style={{fontSize:7,color:"#9a8aaa"}}>{s.desc}</span></div>))}
            {newPassives.map(p=>(<div key={p.id} style={{display:"flex",alignItems:"center",gap:6,marginBottom:4}}><span style={{fontSize:14}}>{p.icon}</span><span style={{fontSize:9,color:"#60c0ff",fontWeight:700}}>{p.name}</span><span style={{fontSize:7,color:"#8aaaaa"}}>{p.desc}</span></div>))}
          </div>
        )}

        {/* Close button */}
        <button onClick={onDone} style={{
          marginTop:8,
          background:"linear-gradient(135deg,rgba(200,169,110,.2),rgba(200,169,110,.08))",
          border:"1px solid #c8a96e50",color:"#e8d090",
          padding:"12px 40px",cursor:"pointer",
          fontSize:12,fontFamily:"inherit",borderRadius:3,
          letterSpacing:".1em",fontWeight:700,
          animation:"fadeIn .4s ease 1.5s both",
        }}>
          ▶ 街へ戻る
        </button>
      </div>
    </div>
  );
}

// ── Rank ──────────────────────────────────────────────────
function getrank(hpPct){
  if(hpPct>=0.9)return{r:"S",c:"#ffc040"};
  if(hpPct>=0.7)return{r:"A",c:"#c060ff"};
  if(hpPct>=0.5)return{r:"B",c:"#4080ff"};
  if(hpPct>=0.3)return{r:"C",c:"#40c880"};
  return{r:"D",c:"#ff5040"};
}

// ── Auth wrapper (outer App) ──────────────────────────────
export default function App(){
  const[authUser,setAuthUser]=useState(null);
  const[authLoading,setAuthLoading]=useState(false);
  const[authError,setAuthError]=useState("");

  if(!authUser) return(
    <LoginScreen
      onLogin={setAuthUser}
      loading={authLoading} setLoading={setAuthLoading}
      error={authError} setError={setAuthError}
    />
  );
  return <GameApp authUser={authUser} onLogout={()=>setAuthUser(null)}/>;
}

// ── Game (inner component, only mounts after login) ───────
function GameApp({authUser,onLogout}){
  const[scene,setScene]=useState("town");
  const[st,setSt]=useState(MAX_ST);
  const[lv,setLv]=useState(1);
  const[exp,setExp]=useState(0);
  const[mxhp,setMxhp]=useState(100);
  const[hp,setHp]=useState(100);
  const[mp,setMp]=useState(MAX_MP);
  const[maxMp,setMaxMp]=useState(MAX_MP);
  const[base,setBase]=useState({atk:10,def:5,spd:5});
  const[eq,setEq]=useState({weapon:null,armor:null,acc:null});
  const TEST_SWORD={
    id:"test_sword", uid:"test_sword_uid", name:"テストプレイソード",
    slot:"weapon", tier:6, icon:"⚔️", rar:"legendary",
    atk:99999, def:999, spd:999,
    fx:{id:"lx_test",label:"⚡ テスト用最強武器",crit:0.99,drain:0.5,magBoost:2.0},
    sell:0,
  };
  const[inv,setInv]=useState([TEST_SWORD]);
  const[spells,setSpells]=useState([]);
  const[passives,setPassives]=useState([]);
  const[gold,setGold]=useState(500); // 初期ゴールド500G
  const[clearedDungeons,setClearedDungeons]=useState(new Set());
  const[saveStatus,setSaveStatus]=useState("");
  const[dungeon,setDungeon]=useState(null);
  const[totalFloors,setTotalFloors]=useState(1);
  const[floor,setFloor]=useState(0);
  const[log,setLog]=useState([]);
  const[loot,setLoot]=useState([]);
  const[legDrop,setLegDrop]=useState(null);
  const[newSpells,setNewSpells]=useState([]);
  const[newPassives,setNewPassives]=useState([]);
  const[rank,setRank]=useState(null);
  const[combo,setCombo]=useState(0);
  const[running,setRunning]=useState(false);
  const[lastResult,setLastResult]=useState(null); // {dungeonName, drops, won, rank}
  const[storyFloor,setStoryFloor]=useState(null);
  const[viewedStories,setViewedStories]=useState(new Set()); // 見たSTORYを記録
  const[memoirFloor,setMemoirFloor]=useState(null); // 回想中のfloorId // dungeon id for story screen
  const[tab,setTab]=useState("dungeons");
  const[shopItems,setShopItems]=useState([]);
  const[shopRefreshCost,setShopRefreshCost]=useState(100);
  const[eqSlot,setEqSlot]=useState("weapon");
  const[selItem,setSelItem]=useState(null);
  const[toast,setToast]=useState(null);
  const[dataLoaded,setDataLoaded]=useState(false); // セーブデータロード完了フラグ
  const logRef=useRef(null);
  const R={
    lv:useRef(1),exp:useRef(0),mxhp:useRef(100),maxMp:useRef(MAX_MP),
    base:useRef({atk:10,def:5,spd:5}),spells:useRef([]),passives:useRef([]),
    eq:useRef({weapon:null,armor:null,acc:null}),inv:useRef([]),
    gold:useRef(0),clearedDungeons:useRef(new Set()),
  };

  // ── Save / Load ──────────────────────────────────────────
  const SAVE_KEY=`kouno_quest_${authUser.id}_v1`;

  async function saveGame(){
    setSaveStatus("保存中…");
    try{
      const safeInv=R.inv.current.map(item=>({
        ...item, uid:String(item.uid),
        atk:item.atk||0, def:item.def||0, spd:item.spd||0,
      }));
      const data={
        lv:R.lv.current, exp:R.exp.current,
        mxhp:R.mxhp.current, hp:R.mxhp.current,
        mp:R.maxMp.current, maxMp:R.maxMp.current,
        base:R.base.current, eq:R.eq.current,
        inv:safeInv,
        spells:R.spells.current.map(s=>s.id),
        passives:R.passives.current.map(p=>p.id),
        gold:R.gold.current,
        clearedDungeons:[...R.clearedDungeons.current],
        viewedStories:[...viewedStories],
        savedAt:Date.now(),
      };
      const json=JSON.stringify(data);
      const ok=await storageSave(SAVE_KEY, json);
      setSaveStatus(ok ? "✓ セーブ済" : "💾 メモリ保存(このセッションのみ)");
      setTimeout(()=>setSaveStatus(""),3000);
    }catch(e){
      setSaveStatus("⚠ "+String(e.message||e).slice(0,30));
      setTimeout(()=>setSaveStatus(""),3000);
    }
  }

  async function loadGame(){
    try{
      const raw=await storageLoad(SAVE_KEY);
      if(raw){
        const d=JSON.parse(raw);
        if(d.lv)       setLv(d.lv);
        if(d.exp!==undefined) setExp(d.exp);
        if(d.mxhp)     setMxhp(d.mxhp);
        if(d.hp)       setHp(d.hp);
        if(d.mp!==undefined)  setMp(d.mp);
        if(d.maxMp)    setMaxMp(d.maxMp);
        if(d.base)     setBase(d.base);
        if(d.eq)       setEq(d.eq);
        if(d.inv){
          const loaded=d.inv.map(item=>({...item,uid:String(item.uid)}));
          // テストソードが消えないよう常に先頭に追加
          const hasTest=loaded.some(i=>i.id==="test_sword");
          setInv(hasTest?loaded:[TEST_SWORD,...loaded]);
        }
        if(d.spells)   setSpells(SPELLS.filter(s=>d.spells.includes(s.id)));
        if(d.passives) setPassives(PASSIVES.filter(p=>d.passives.includes(p.id)));
        if(d.gold!==undefined) setGold(d.gold);
        if(d.clearedDungeons)  setClearedDungeons(new Set(d.clearedDungeons));
        if(d.viewedStories)    setViewedStories(new Set(d.viewedStories));
      }
    }catch(e){
      console.error("Load failed:",e);
    } finally {
      setDataLoaded(true);
    }
  }

  // ── Effects (all after state declarations) ────────────────
  useEffect(()=>{ loadGame(); },[]);
  useEffect(()=>{ setShopItems(generateShop(1)); },[]);
  useEffect(()=>{
    const id=setInterval(()=>{ if(!running) saveGame(); },60000);
    return()=>clearInterval(id);
  // eslint-disable-next-line
  },[running]);
  useEffect(()=>{R.lv.current=lv},[lv]);
  useEffect(()=>{R.exp.current=exp},[exp]);
  useEffect(()=>{R.mxhp.current=mxhp},[mxhp]);
  useEffect(()=>{R.maxMp.current=maxMp},[maxMp]);
  useEffect(()=>{R.base.current=base},[base]);
  useEffect(()=>{R.spells.current=spells},[spells]);
  useEffect(()=>{R.passives.current=passives},[passives]);
  useEffect(()=>{R.eq.current=eq},[eq]);
  useEffect(()=>{R.inv.current=inv},[inv]);
  // テストソードをロード後に一度だけ確認して保証（無限ループ防止のためdataLoadedのみ依存）
  useEffect(()=>{
    if(dataLoaded){
      setInv(prev=>prev.some(i=>i.id==="test_sword")?prev:[TEST_SWORD,...prev]);
    }
  },[dataLoaded]); // eslint-disable-line
  useEffect(()=>{R.gold.current=gold},[gold]);
  useEffect(()=>{R.clearedDungeons.current=clearedDungeons},[clearedDungeons]);
  useEffect(()=>{const id=setInterval(()=>setSt(s=>Math.min(MAX_ST,s+1)),60000);return()=>clearInterval(id);},[]);
  useEffect(()=>{if(logRef.current)logRef.current.scrollTop=logRef.current.scrollHeight;},[log]);
  const stats=calcStatsWithInv(base,eq,inv);
  const xpN=lv*100;
  const hpPct=hp/mxhp,hpC=hpPct>.5?"#40c880":hpPct>.25?"#ffb040":"#ff5040";
  const showToast=(msg,c="#40c880")=>{setToast({msg,c});setTimeout(()=>setToast(null),2500);};
  const addLog=(text,c="#c8b880")=>setLog(l=>[...l,{text,c,id:Date.now()+Math.random()}]);
  const sleep=ms=>new Promise(r=>setTimeout(r,ms));

  function sellItem(item){
    const price=RARITY[item.rar||"common"]?.sell||5;
    setInv(i=>i.filter(x=>x.uid!==item.uid));
    setGold(g=>g+price);
    // Unequip if currently equipped (compare by uid)
    if(eq.weapon===item.uid||eq.armor===item.uid||eq.acc===item.uid)
      setEq(e=>({...e,[item.slot]:null}));
    setSelItem(null);
    return price;
  }

  function autoSell(threshold="uncommon"){
    const order=["common","uncommon","rare","epic","legendary"];
    const tIdx=order.indexOf(threshold);
    let totalG=0;
    const equippedUids=new Set([eq.weapon,eq.armor,eq.acc].filter(Boolean));
    setInv(i=>{
      const keep=[],sold=[];
      i.forEach(item=>{
        const rIdx=order.indexOf(item.rar||"common");
        // Don't sell equipped items or non-equipment
        if(item.slot&&rIdx<=tIdx&&!equippedUids.has(item.uid)){sold.push(item);}
        else keep.push(item);
      });
      sold.forEach(item=>{totalG+=RARITY[item.rar||"common"].sell;});
      return keep;
    });
    if(totalG>0)setGold(g=>g+totalG);
    return totalG;
  }

  function autoEquip(){
    const score=i=>(i.atk||0)*1.5+(i.def||0)+(i.spd||0)*.5+(i.fx?.allStat||0)*3+(i.fx?.crit||0)*30+(i.fx?.drain||0)*20;
    ["weapon","armor","acc"].forEach(slot=>{
      const cs=inv.filter(i=>i.slot===slot);
      if(!cs.length) return;
      // Always pick the absolute best — no comparison with current equip needed
      const best=cs.reduce((a,b)=>score(b)>score(a)?b:a);
      setEq(e=>({...e,[slot]:best.uid}));
    });
  }

  function buyItem(shopItem){
    if(gold<shopItem.price) return;
    setGold(g=>g-shopItem.price);
    setShopItems(s=>s.filter(i=>i.uid!==shopItem.uid));

    if(shopItem.type==="boost"){
      if(shopItem.stat==="atk") setBase(b=>({...b,atk:b.atk+shopItem.val}));
      else if(shopItem.stat==="def") setBase(b=>({...b,def:b.def+shopItem.val}));
      else if(shopItem.stat==="hp"){setMxhp(h=>h+shopItem.val);setHp(h=>h+shopItem.val);}
      else if(shopItem.stat==="mp"){setMaxMp(m=>m+shopItem.val);setMp(m=>m+shopItem.val);}
    } else if(shopItem.type==="stamina"){
      setSt(s=>Math.min(MAX_ST,s+shopItem.val));
    } else if(shopItem.type==="hp"){
      setHp(h=>Math.min(mxhp,h+shopItem.val));
    } else if(shopItem.type==="mp"){
      setMp(m=>Math.min(maxMp,m+shopItem.val));
    } else if(shopItem.slot){
      // Equipment: add a fresh copy to inventory
      const bought={...shopItem, uid:"inv_"+Date.now()+Math.random()};
      setInv(i=>[...i,bought]);
    }
  }

  function refreshShop(){
    if(gold<shopRefreshCost) return;
    setGold(g=>g-shopRefreshCost);
    setShopItems(generateShop(lv));
    setShopRefreshCost(c=>c+50); // Gets more expensive
  }
  async function startDungeon(d){
    // Same unlock logic as the UI
    const prevCleared = d.id===1 || clearedDungeons.has(d.id-1);
    const locked = !prevCleared && lv < d.lv;
    if(locked||running) return;

    setSt(s=>s-d.sc);setDungeon(d);setTotalFloors(d.f);setFloor(0);setLog([]);setLoot([]);
    setNewSpells([]);setNewPassives([]);setLegDrop(null);setRank(null);setCombo(0);
    setHp(R.mxhp.current);setMp(R.maxMp.current);setScene("explore");setRunning(true);

    let chp=R.mxhp.current,cmp=R.maxMp.current,cMaxMp=R.maxMp.current;
    let cLv=R.lv.current,cExp=R.exp.current,cMxhp=R.mxhp.current;
    let cBase={...R.base.current},cSpells=[...R.spells.current],cPassives=[...R.passives.current];
    let cEq={...R.eq.current},cInv=[...R.inv.current];
    let cCombo=0,usedRevive=false;
    const drops=[],gainedSp=[],gainedPa=[];
    setLog([]);

    const liveStats=()=>calcStatsWithInv(cBase,cEq,cInv);

    function lvUp(g){
      cExp+=g;
      while(cExp>=cLv*100){
        cExp-=cLv*100;cLv++;cMxhp+=15;cMaxMp=Math.min(cMaxMp+5,120);
        cBase={atk:cBase.atk+2,def:cBase.def+1,spd:cBase.spd+1};
        chp=Math.min(cMxhp,chp+25);cmp=Math.min(cMaxMp,cmp+10);
        // Update ALL relevant state immediately so display is correct mid-dungeon
        setHp(chp);setMxhp(cMxhp);setMp(cmp);setMaxMp(cMaxMp);
        addLog(`🌟 Lv.${cLv} レベルアップ！ ATK+2 DEF+1 SPD+1`,"#ffc040");
        SPELLS.filter(s=>s.lv===cLv&&!cSpells.find(x=>x.id===s.id)).forEach(s=>{cSpells.push(s);gainedSp.push(s);addLog(`✨ 魔法習得: ${s.icon}${s.name}`,"#c060ff");});
        PASSIVES.filter(p=>p.lv===cLv&&!cPassives.find(x=>x.id===p.id)).forEach(p=>{cPassives.push(p);gainedPa.push(p);addLog(`💡 パッシブ解放: ${p.icon}${p.name} 「${p.desc}」`,"#60c0ff");});
      }
    }

    try {

    addLog(`━━ ${d.name} 突入 ━━`,"#c8a96e");await sleep(350);

    for(let f=1;f<=d.f;f++){
      setFloor(f);const boss=f===d.f;
      addLog(`\n── ${f}F${boss?" 【BOSS】":""}──`,"#8aaabb");await sleep(300);

      if(!boss&&Math.random()<.45){
        const ev=EVENTS[Math.floor(Math.random()*EVENTS.length)];
        addLog(`${ev.icon} ${ev.label}`,"#90c0d8");await sleep(240);
        if(ev.eff==="heal"){const h=Math.floor(cMxhp*.3);chp=Math.min(cMxhp,chp+h);setHp(chp);addLog(`  ❤️ HP+${h}`,"#40c880");}
        else if(ev.eff==="mp"){cmp=Math.min(cMaxMp,cmp+20);setMp(cmp);addLog(`  🔮 MP+20`,"#8080ff");}
        else if(ev.eff==="dmg"){const dmg=Math.floor(d.lv*4+6);chp=Math.max(1,chp-dmg);setHp(chp);addLog(`  💥 -${dmg}HP`,"#ff6040");}
        else if(ev.eff==="item"){
          const pool=getDropPool(d.lv);const item=pool[Math.floor(Math.random()*pool.length)];const rar=rollRar();
          const dropped=item.slot?applyRarity(item,rar):{...item,rar,uid:Date.now()+Math.random()};
          drops.push(dropped);addLog(`  ${item.icon||"📦"}${item.name}[${RARITY[rar].label}]入手！`,RARITY[rar].color);
          if(rar==="legendary")setLegDrop(dropped);
        }
        else if(ev.eff==="buff"){addLog(`  ✨ ATK+3 の祝福`,"#c8a96e");}
        await sleep(280);
      }

      const eName=boss?d.boss:d.e[Math.floor(Math.random()*d.e.length)];
      const cnt=boss?1:Math.floor(Math.random()*2)+1;
      const mul=boss?2.0:1;
      const enemies=Array.from({length:cnt},()=>({
        name:eName,
        hp:  Math.floor((d.lv*22+35)*mul),
        maxHp:Math.floor((d.lv*22+35)*mul),
        atk: Math.floor((d.lv*4.5+5)*(boss?1.8:1)), // ボスATKは別倍率で抑える
        def: Math.floor((d.lv*2.2+2)*mul),
      }));
      if(boss)addLog(`\n💀 BOSS: ${eName}が現れた！`,"#ff4040");
      else addLog(`  ⚔️ ${cnt>1?cnt+"体の":""}${eName}が現れた！`,"#d0b870");
      await sleep(280);

      let surv=[...enemies],shielded=false;

      for(let r=0;r<60;r++){  // Bug4: 30→60ラウンドに引き上げ
        if(!surv.length||chp<=0)break;
        const t=surv[0];
        const S=liveStats();

        const bersAtk=cPassives.find(p=>p.id==="p4")&&chp/cMxhp<0.3;
        const atkMul=bersAtk?1.5:1;

        const usableAtk=cSpells.filter(sp=>sp.mp<=cmp&&(sp.type==="atk"||sp.type==="atkIgn"));
        const usableHeal=cSpells.filter(sp=>sp.mp<=cmp&&sp.type==="heal");
        const usableBuff=cSpells.filter(sp=>sp.mp<=cmp&&sp.type==="buff");

        const shouldHeal=usableHeal.length&&chp/cMxhp<=0.30;
        const shouldBuff=usableBuff.length&&!shielded&&chp/cMxhp<=0.50;
        const shouldAtk=usableAtk.length&&Math.random()<.35;

        if(shouldHeal){
          const sp=usableHeal[0];cmp-=sp.mp;setMp(cmp);
          const h=Math.floor(cMxhp*sp.power);chp=Math.min(cMxhp,chp+h);setHp(chp);
          addLog(`  ${sp.icon}${sp.name}！HP+${h}回復`,"#40c880");
        } else if(shouldBuff){
          const sp=usableBuff[0];cmp-=sp.mp;setMp(cmp);
          shielded=true;addLog(`  ${sp.icon}${sp.name}！被ダメ半減`,"#8080c0");
        } else if(shouldAtk){
          const sp=usableAtk[Math.floor(Math.random()*usableAtk.length)];cmp-=sp.mp;setMp(cmp);
          const raw=Math.floor(S.atk*sp.power*atkMul+Math.random()*10);
          const dmg=sp.type==="atkIgn"?raw:Math.max(1,raw-t.def);
          // Bug3 fix: sum magBoost across all equipped items
          const magBoost=1+[cEq.weapon,cEq.armor,cEq.acc].reduce((sum,uid)=>{
            const it=cInv.find(i=>i.uid===uid);return sum+(it?.fx?.magBoost||0);
          },0);
          const finalDmg=Math.floor(dmg*magBoost);
          t.hp-=finalDmg;
          addLog(`  ${sp.icon}${sp.name}！→${t.name}に${finalDmg}魔法ダメージ`,"#b070ff");
        } else {
          const raw=Math.max(1,Math.floor(S.atk*atkMul)-t.def+Math.floor(Math.random()*7)-3);
          // Bug3 fix: check legendary crit bonus across all equipped items
          const legCrit=[cEq.weapon,cEq.armor,cEq.acc].reduce((sum,uid)=>{
            const it=cInv.find(i=>i.uid===uid);return sum+(it?.fx?.crit||0);
          },0);
          const crit=Math.random()<(0.1+legCrit);
          // Bug3 fix: check legendary extraHit across equipped items
          const legExtra=[cEq.weapon,cEq.armor,cEq.acc].some(uid=>cInv.find(i=>i.uid===uid)?.fx?.extraHit);
          const extraHit=(cPassives.find(p=>p.id==="p2")&&Math.random()<.15)||legExtra;
          const dmg=Math.max(1,raw*(crit?2:1));
          t.hp-=dmg;
          addLog(`  ${crit?"💥クリティカル！":""}KOUNO→${t.name}に${dmg}ダメージ`,crit?"#ffc040":"#c8b880");
          if(extraHit){const ed=Math.max(1,Math.floor(S.atk*.5));t.hp-=ed;addLog(`  　⚔️ 追撃！${ed}ダメージ`,"#ffa040");}
          // Vampire passive
          if(cPassives.find(p=>p.id==="p3")){const drain=Math.floor(dmg*.05);chp=Math.min(cMxhp,chp+drain);if(drain>0)setHp(chp);}
          // Bug3 fix: legendary drain effect
          const legDrain=[cEq.weapon,cEq.armor,cEq.acc].reduce((sum,uid)=>{
            const it=cInv.find(i=>i.uid===uid);return sum+(it?.fx?.drain||0);
          },0);
          if(legDrain>0){const d=Math.floor(dmg*legDrain);chp=Math.min(cMxhp,chp+d);setHp(chp);}
          cCombo++;setCombo(cCombo);
        }
        await sleep(220);

        if(t.hp<=0){
          const xp=Math.floor(d.lv*9+(boss?70:18));
          const comboBonus=cCombo>=5?Math.floor(xp*.2):0;
          addLog(`  ✓${t.name}を倒した！EXP+${xp}${comboBonus>0?` コンボボーナス+${comboBonus}`:""}`,"#40c880");
          lvUp(xp+comboBonus);cCombo=0;setCombo(0);surv=surv.slice(1);
          if(Math.random()<.68){
            const pool=getDropPool(d.lv).filter(p=>p.slot);
            if(pool.length){const item=pool[Math.floor(Math.random()*pool.length)];const rar=rollRar();
              const dropped=applyRarity(item,rar);drops.push(dropped);
              addLog(`  ${dropped.icon||"⚔️"}${dropped.name}[${RARITY[rar].label}]ドロップ！`,RARITY[rar].color);
              if(rar==="legendary")setLegDrop(dropped);}
          }
          await sleep(220);continue;
        }

        for(const en of surv){
          let ed=Math.max(1,en.atk-S.def+Math.floor(Math.random()*5)-2);
          if(shielded){ed=Math.floor(ed*.5);shielded=false;}
          const red=[cEq.weapon,cEq.armor,cEq.acc].reduce((sum,uid)=>{
            const it=cInv.find(i=>i.uid===uid);return sum+(it?.fx?.dmgReduce||0);
          },0);
          ed=Math.floor(ed*(1-Math.min(red,0.8)));
          if(chp-ed<=0&&cPassives.find(p=>p.id==="p5")&&!usedRevive){ed=chp-1;usedRevive=true;addLog(`  💫 不死の意志発動！`,"#ffc040");}
          chp=Math.max(0,chp-ed);setHp(chp);cCombo=0;setCombo(0);
          addLog(`  ${en.name}→KOUNOに${ed}ダメージ(HP:${chp})`,"#ff7050");
          // Bug7 fix: counter damage + immediate kill check
          if(cPassives.find(p=>p.id==="p1")&&Math.random()<.2&&chp>0){
            const ctr=Math.max(1,Math.floor(S.atk*.4));en.hp-=ctr;
            addLog(`  🔄 カウンター！${ctr}ダメージ`,"#60d0a0");
            if(en.hp<=0){addLog(`  ✓ カウンターで撃破！`,"#40c880");break;}
          }
          await sleep(190);if(chp<=0)break;
        }
        // Fix4: check death immediately after enemy attacks
        if(chp<=0){addLog("\n☠️ KOUNOは力尽きた……","#ff4040");setHp(0);break;}
        // Remove dead enemies from surv after enemy attack phase
        surv=surv.filter(en=>en.hp>0);
      }
      if(chp<=0) break; // floor loop exit
    }

    const won=chp>0;
    if(won){
      const rk=getrank(chp/cMxhp);setRank(rk);
      addLog(`\n🏆 ${d.name} クリア！ランク ${rk.r}`,rk.c);
      const g=d.lv*18+Math.floor(Math.random()*d.lv*25);
      R.gold.current+=g; setGold(R.gold.current);
      addLog(`  💰+${g}G`,"#c8a96e");
      lvUp(d.lv*35+60);
      setClearedDungeons(prev=>{const next=new Set(prev);next.add(d.id);return next;});
    }
    // Save last dungeon result for display
    setLastResult({
      dungeonName:d.name, dungeonIcon:d.icon,
      drops:[...drops], won,
      rank: won ? getrank(chp/cMxhp) : null,
    });
    setLv(cLv);setExp(cExp);setMxhp(cMxhp);setMaxMp(cMaxMp);setBase(cBase);setSpells(cSpells);setPassives(cPassives);
    setHp(Math.max(0,chp));setMp(cmp);setGold(R.gold.current);
    if(gainedSp.length)setNewSpells(gainedSp);if(gainedPa.length)setNewPassives(gainedPa);
    // Inventory updated, show result screen
    const newInv=[...cInv,...drops];
    setInv(newInv);
    setStoryFloor(d.id);
    setScene("result"); // ← リザルト画面へ
    setTimeout(()=>saveGame(), 800); // refが更新されてからセーブ
    } catch(err) {
      console.error("Dungeon error:", err);
      setScene("town");
    } finally {
      setRunning(false);
    }
  }

  function collectLoot(){
    setLoot([]);setLegDrop(null);setNewSpells([]);setNewPassives([]);
    // Show story if won, else go to town
    if(lastResult?.won && SE[storyFloor]){
      setScene("story");
    } else {
      setScene("town");
      setTimeout(()=>saveGame(), 300);
    }
  }
  function storyDone(){
    if(storyFloor) setViewedStories(prev=>new Set([...prev, storyFloor]));
    setStoryFloor(null);
    setScene("town");
    setTimeout(()=>saveGame(), 300);
  }
  function equipItem(item){
    setEq(e=>({...e,[item.slot]:item.uid})); // uid-based!
    setSelItem(null);
  }

  const slotN={weapon:"⚔️武器",armor:"🛡️防具",acc:"💍アクセ"};
  const equippedItem=(slot)=>inv.find(i=>i.uid===eq[slot]);

  // ロード完了まではスピナー
  if(!dataLoaded) return(
    <div style={{background:"#06080c",minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:12,fontFamily:"'Courier New',monospace"}}>
      <div style={{fontSize:28}}>⚔️</div>
      <div style={{fontSize:11,color:"#c8a96e",letterSpacing:".15em"}}>セーブデータを読み込み中…</div>
      <div style={{fontSize:9,color:"#4a3a1a",marginTop:4}}>
        {authUser.type==="wallet"?"🦊 "+authUser.name:"👤 旅人"}
      </div>
    </div>
  );

  return(
    <div style={{background:"#06080c",minHeight:"100vh",color:"#e0cca0",fontFamily:"'Courier New',monospace",display:"flex",flexDirection:"column",maxWidth:480,margin:"0 auto"}}>
      <style>{`
        @keyframes fi{from{opacity:0;transform:translateY(-4px)}to{opacity:1;transform:translateY(0)}}
        @keyframes lgP{0%,100%{box-shadow:0 0 14px #ffc04050}50%{box-shadow:0 0 35px #ffc040a0}}
        @keyframes sP{0%,100%{box-shadow:0 0 8px #c060ff40}50%{box-shadow:0 0 20px #c060ff80}}
        @keyframes toastIn{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}
        @keyframes fadeIn{from{opacity:0}to{opacity:1}}
        @keyframes slideUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}
        @keyframes zoomIn{from{opacity:0;transform:scale(.7)}to{opacity:1;transform:scale(1)}}
        @keyframes rankBounce{0%{transform:scale(0) rotate(-20deg)}60%{transform:scale(1.2) rotate(5deg)}100%{transform:scale(1) rotate(0)}}
        @keyframes shimmer{0%,100%{opacity:.6}50%{opacity:1}}
        @keyframes particle{0%{transform:translateY(0) rotate(0);opacity:1}100%{transform:translateY(-80px) rotate(360deg);opacity:0}}
        @keyframes lgBig{0%,100%{box-shadow:0 0 30px #ffc04060}50%{box-shadow:0 0 60px #ffc040a0,0 0 100px #ffc04040}}
        *{box-sizing:border-box}
        ::-webkit-scrollbar{width:3px}
        ::-webkit-scrollbar-track{background:#06080c}
        ::-webkit-scrollbar-thumb{background:#2a2010}
        button:hover:not(:disabled){filter:brightness(1.15)}
      `}</style>

      {/* Toast notification */}
      {toast&&(
        <div style={{position:"fixed",bottom:20,left:"50%",transform:"translateX(-50%)",zIndex:100,
          background:"rgba(6,8,12,.95)",border:`1px solid ${toast.c}60`,
          color:toast.c,padding:"8px 18px",borderRadius:3,fontSize:11,
          animation:"toastIn .3s ease",whiteSpace:"nowrap",
          boxShadow:`0 0 16px ${toast.c}30`}}>
          {toast.msg}
        </div>
      )}

      {/* ── Header ── */}
      <div style={{background:"rgba(6,8,12,.99)",borderBottom:"1px solid #2a2010",position:"sticky",top:0,zIndex:20}}>
        <div style={{padding:"9px 14px 4px",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
          <div>
            <div style={{fontSize:15,fontWeight:700,color:"#e8d090",letterSpacing:".12em"}}>⚔️ KOUNO QUEST</div>
            <div style={{fontSize:8,color:"#c8a870",marginTop:1}}>
              Lv.{lv} · HP{hp}/{mxhp} · {stats.atk}ATK · {stats.def}DEF · 💰{gold}G{combo>=3?` · 🔥×${combo}`:""}
            </div>
            <div style={{fontSize:7,color:"#4a3a1a",marginTop:1,display:"flex",alignItems:"center",gap:6}}>
              <span>{authUser.type==="wallet"?"🦊":authUser.type==="google"?"🔴":"👤"} {authUser.name}</span>
              <button onClick={onLogout} style={{background:"none",border:"1px solid #3a2a0a",color:"#4a3a1a",padding:"1px 6px",cursor:"pointer",fontSize:7,fontFamily:"inherit",borderRadius:2}}>ログアウト</button>
            </div>
          </div>
          <div style={{textAlign:"right",fontSize:8,color:"#8090a8"}}>
            {saveStatus&&<div style={{color:"#40c880",marginBottom:2}}>{saveStatus}</div>}
            EXP {exp}/{xpN}
          </div>
        </div>
        <STBar st={st}/>
        <div style={{display:"flex",borderTop:"1px solid #1a1808",marginTop:5}}>
          {[["dungeons","ダンジョン"],["equipment","装備"],["shop","ショップ"],["spells","魔法"],["passives","パッシブ"],["inventory","所持品"],["memoir","回想"]].map(([id,lbl])=>(
            <button key={id}
              onClick={()=>{if(scene==="explore"||scene==="story")return;setScene("town");setTab(id);}}
              disabled={scene==="explore"||scene==="story"}
              style={{flex:1,background:"none",border:"none",
                borderBottom:(scene==="town"&&tab===id)?"2px solid #c8a96e":"2px solid transparent",
                color:(scene==="explore"||scene==="story")?"#2a1a08":(scene==="town"&&tab===id)?"#c8a96e":"#c8a870",
                padding:"7px 0",cursor:(scene==="explore"||scene==="story")?"not-allowed":"pointer",
                fontSize:8,fontFamily:"inherit",opacity:(scene==="explore"||scene==="story")?.4:1
              }}>{lbl}</button>
          ))}
        </div>
      </div>

      <div style={{flex:1,overflowY:"auto"}}>

        {/* DUNGEONS */}
        {scene==="town"&&tab==="dungeons"&&(
          <div style={{padding:12}}>
            {/* Fix 6: Last dungeon result */}
            {lastResult&&(
              <div style={{
                background: lastResult.won?"rgba(200,169,110,.06)":"rgba(255,80,64,.06)",
                border:`1px solid ${lastResult.won?"#c8a96e25":"#ff504025"}`,
                borderRadius:3,padding:10,marginBottom:12,
              }}>
                <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:6}}>
                  <div style={{fontSize:9,color:lastResult.won?"#c8a96e":"#ff6040",fontWeight:700}}>
                    {lastResult.dungeonIcon} {lastResult.dungeonName} {lastResult.won?"クリア":"全滅"}
                    {lastResult.rank&&<span style={{marginLeft:6,color:lastResult.rank.c}}>Rank {lastResult.rank.r}</span>}
                  </div>
                  <button onClick={()=>setLastResult(null)} style={{background:"none",border:"none",color:"#4a3a1a",cursor:"pointer",fontSize:10,padding:"0 4px"}}>✕</button>
                </div>
                {lastResult.drops.length>0?(
                  <>
                    <div style={{fontSize:7,color:"#8a7a5a",marginBottom:5}}>ドロップ {lastResult.drops.length}個</div>
                    <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                      {lastResult.drops.map((item,i)=>(
                        <div key={i} style={{
                          background:"#0a0806",border:`1px solid ${RARITY[item.rar||"common"].color}30`,
                          borderRadius:2,padding:"4px 7px",
                          display:"flex",alignItems:"center",gap:4,
                          animation:item.rar==="legendary"?"lgP 2s infinite":"none",
                        }}>
                          <span style={{fontSize:12}}>{item.icon||"⚔️"}</span>
                          <div>
                            <div style={{fontSize:7,color:RARITY[item.rar||"common"].color}}>{item.name}</div>
                            {item.slot&&<div style={{fontSize:6,color:"#6a7a50"}}>{[["A",item.atk],["D",item.def],["S",item.spd]].filter(([,v])=>v!==0).map(([l,v])=>`${l}${v>0?"+":""}${v}`).join(" ")}</div>}
                          </div>
                        </div>
                      ))}
                    </div>
                  </>
                ):<div style={{fontSize:7,color:"#4a3a1a"}}>ドロップなし</div>}
              </div>
            )}
            {DUNGEONS.map(d=>{
              const prevCleared = d.id===1 || clearedDungeons.has(d.id-1);
              const locked = !prevCleared && lv < d.lv;
              const justUnlocked = prevCleared && lv < d.lv;
              const isCleared = clearedDungeons.has(d.id);
              return(
                <div key={d.id} style={{background:locked?"rgba(8,6,4,.6)":"rgba(12,10,6,.9)",border:`1px solid ${locked?"#181208":isCleared?"#c8a96e40":"#2a2010"}`,borderRadius:3,padding:10,marginBottom:7,opacity:locked?.4:1}}>
                  <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:5}}>
                    <div style={{display:"flex",alignItems:"center",gap:7}}>
                      <span style={{fontSize:17}}>{d.icon}</span>
                      <div>
                        <div style={{display:"flex",alignItems:"center",gap:6}}>
                          <div style={{fontSize:10,color:locked?"#7a6040":"#e8d090",fontWeight:700}}>{d.name}</div>
                          {isCleared&&<span style={{fontSize:7,color:"#c8a96e",border:"1px solid #c8a96e40",padding:"0 4px"}}>✓クリア済</span>}
                          {justUnlocked&&!isCleared&&<span style={{fontSize:7,color:"#40c880",border:"1px solid #40c88040",padding:"0 4px"}}>🔓解放！</span>}
                        </div>
                        <div style={{fontSize:7,color:"#8aaabb"}}>推奨Lv.{d.lv} · {d.f}F · ボス:{d.boss}</div>
                      </div>
                    </div>
                  </div>
                  <button onClick={()=>startDungeon(d)} disabled={locked||running} style={{width:"100%",background:locked?"rgba(60,20,10,.3)":"linear-gradient(135deg,rgba(200,169,110,.15),rgba(200,169,110,.04))",border:`1px solid ${locked?"#ff504020":"#c8a96e35"}`,color:locked?"#7a6040":"#c8a96e",padding:"6px",cursor:locked?"not-allowed":"pointer",fontSize:8,letterSpacing:".08em",fontFamily:"inherit",borderRadius:2}}>
                    {locked?"🔒 前のダンジョンをクリアして解放":"▶ 突入する"}
                  </button>
                </div>
              );
            })}
          </div>
        )}

        {/* EQUIPMENT */}
        {scene==="town"&&tab==="equipment"&&(
          <div style={{padding:12}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:9}}>
              <div style={{display:"flex",gap:0}}>
                {["weapon","armor","acc"].map(s=>(
                  <button key={s} onClick={()=>{setEqSlot(s);setSelItem(null);}} style={{background:"none",border:"none",borderBottom:eqSlot===s?"2px solid #c8a96e":"2px solid transparent",color:eqSlot===s?"#c8a96e":"#c8a870",padding:"4px 9px",cursor:"pointer",fontSize:8,fontFamily:"inherit"}}>{slotN[s]}</button>
                ))}
              </div>
              <button onClick={autoEquip} style={{background:"rgba(200,169,110,.07)",border:"1px solid #c8a96e25",color:"#c8a96e",padding:"3px 9px",cursor:"pointer",fontSize:8,fontFamily:"inherit",borderRadius:2}}>⚡AUTO装備</button>
            </div>

            {/* Current equipped */}
            {(()=>{const cur=equippedItem(eqSlot);return(
              <div style={{background:"rgba(200,169,110,.04)",border:"1px solid #c8a96e18",borderRadius:2,padding:9,marginBottom:9}}>
                <div style={{fontSize:7,color:"#c8a870",marginBottom:4}}>装備中</div>
                {cur?(<div style={{display:"flex",alignItems:"center",gap:7}}>
                  <span style={{fontSize:18}}>{cur.icon||"⚔️"}</span>
                  <div style={{flex:1}}>
                    <div style={{display:"flex",alignItems:"center",gap:5,marginBottom:3}}><span style={{fontSize:10,color:"#e8d090",fontWeight:700}}>{cur.name}</span>{cur.rar&&<RT r={cur.rar}/>}</div>
                    <div style={{display:"flex",gap:7,fontSize:9}}>{[["ATK",cur.atk,"#ff8060"],["DEF",cur.def,"#4080ff"],["SPD",cur.spd,"#40c880"]].map(([l,v,c])=>v!==0&&<span key={l} style={{color:c}}>{l}<b>{v>0?"+":""}{v}</b></span>)}</div>
                    {cur.fx&&<div style={{fontSize:8,color:"#ffc040",marginTop:2}}>{cur.fx.label}</div>}
                  </div>
                </div>):<div style={{fontSize:8,color:"#a08050",textAlign:"center"}}>（未装備）</div>}
              </div>
            );})()}

            {/* Inventory items for slot */}
            <div style={{fontSize:7,color:"#c8a870",marginBottom:5}}>所持品 ({inv.filter(i=>i.slot===eqSlot).length}件)</div>
            {inv.filter(i=>i.slot===eqSlot).length===0&&<div style={{fontSize:8,color:"#a08050",textAlign:"center",padding:14}}>このスロットの装備なし</div>}
            {inv.filter(i=>i.slot===eqSlot).map((item,idx)=>{
              const cur=equippedItem(eqSlot);
              const da=(item.atk||0)-(cur?.atk||0),dd=(item.def||0)-(cur?.def||0),ds=(item.spd||0)-(cur?.spd||0);
              const sel=selItem===item.uid,isEq=eq[eqSlot]===item.uid; // uid-based!
              const sellP=RARITY[item.rar||"common"].sell;
              return(
                <div key={item.uid||idx} onClick={()=>setSelItem(sel?null:item.uid)} style={{background:sel?"rgba(200,169,110,.07)":"#0a0806",border:`1px solid ${RARITY[item.rar||"common"].color}28`,borderRadius:2,padding:9,marginBottom:5,cursor:"pointer",animation:item.rar==="legendary"?"lgP 2s infinite":"none"}}>
                  <div style={{display:"flex",gap:7,alignItems:"center"}}>
                    <span style={{fontSize:17}}>{item.icon||"⚔️"}</span>
                    <div style={{flex:1}}>
                      <div style={{display:"flex",alignItems:"center",gap:5,marginBottom:2}}><span style={{fontSize:9,color:RARITY[item.rar||"common"].color}}>{item.name}</span><RT r={item.rar||"common"}/>{isEq&&<span style={{fontSize:7,color:"#c8a96e",border:"1px solid #c8a96e25",padding:"0 3px"}}>装備中</span>}</div>
                      <div style={{display:"flex",gap:7,fontSize:9,marginBottom:2}}>{[["ATK",item.atk,"#ff8060"],["DEF",item.def,"#4080ff"],["SPD",item.spd,"#40c880"]].map(([l,v,c])=>v!==0&&<span key={l} style={{color:c}}>{l}<b>{v>0?"+":""}{v}</b></span>)}</div>
                      {item.fx&&<div style={{fontSize:7,color:"#ffc040",marginBottom:2}}>{item.fx.label}</div>}
                      <div style={{display:"flex",gap:4,fontSize:7}}>{[[da,"ATK"],[dd,"DEF"],[ds,"SPD"]].map(([d2,l])=>d2!==0&&<span key={l} style={{color:d2>0?"#40c880":"#ff5040"}}>{l}{d2>0?"▲":"▼"}{Math.abs(d2)}</span>)}</div>
                    </div>
                  </div>
                  {sel&&<div style={{display:"flex",gap:5,marginTop:6}}>
                    {!isEq&&<button onClick={e=>{e.stopPropagation();equipItem(item);}} style={{flex:2,background:"rgba(200,169,110,.1)",border:"1px solid #c8a96e25",color:"#c8a96e",padding:"4px",cursor:"pointer",fontSize:8,fontFamily:"inherit",borderRadius:2}}>⚔️ 装備</button>}
                    <button onClick={e=>{e.stopPropagation();sellItem(item);setSelItem(null);}} style={{flex:1,background:"rgba(255,160,64,.08)",border:"1px solid #ffa04025",color:"#ffa040",padding:"4px",cursor:"pointer",fontSize:8,fontFamily:"inherit",borderRadius:2}}>💰 {sellP}Gで売却</button>
                  </div>}
                </div>
              );
            })}

            {/* Stats */}
            <div style={{marginTop:10,background:"#0a0806",border:"1px solid #2a2010",borderRadius:2,padding:10}}>
              <div style={{fontSize:7,color:"#c8a870",marginBottom:6}}>── 合計ステータス ──</div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:5}}>
                {[["ATK",stats.atk,"#ff8060","⚔️"],["DEF",stats.def,"#4080ff","🛡️"],["SPD",stats.spd,"#40c880","💨"]].map(([l,v,c,ic])=>(
                  <div key={l} style={{textAlign:"center",background:"#080603",border:`1px solid ${c}18`,borderRadius:2,padding:"5px 3px"}}>
                    <div style={{fontSize:10,marginBottom:1}}>{ic}</div><div style={{fontSize:14,color:c,fontWeight:700}}>{v}</div><div style={{fontSize:7,color:"#c8a870"}}>{l}</div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* SHOP */}
        {scene==="town"&&tab==="shop"&&(
          <div style={{padding:12}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
              <div>
                <div style={{fontSize:10,color:"#e8d090",fontWeight:700}}>🏪 ショップ</div>
                <div style={{fontSize:7,color:"#c8a870",marginTop:1}}>所持金: <span style={{color:"#ffc040",fontWeight:700}}>💰 {gold}G</span></div>
              </div>
              <button onClick={refreshShop} disabled={gold<shopRefreshCost} style={{background:"rgba(200,169,110,.08)",border:`1px solid ${gold>=shopRefreshCost?"#c8a96e30":"#7a6040"}`,color:gold>=shopRefreshCost?"#c8a96e":"#7a6040",padding:"5px 10px",cursor:gold>=shopRefreshCost?"pointer":"not-allowed",fontSize:8,fontFamily:"inherit",borderRadius:2}}>
                🔄 ラインナップ更新 ({shopRefreshCost}G)
              </button>
            </div>

            {shopItems.length===0&&(
              <div style={{fontSize:9,color:"#a08050",textAlign:"center",padding:24}}>
                在庫なし。更新してください。
                <br/><button onClick={()=>setShopItems(generateShop(lv))} style={{marginTop:10,background:"rgba(200,169,110,.08)",border:"1px solid #c8a96e30",color:"#c8a96e",padding:"5px 12px",cursor:"pointer",fontSize:8,fontFamily:"inherit",borderRadius:2}}>無料で補充（初回）</button>
              </div>
            )}

            {shopItems.map((item,i)=>{
              const canBuy=gold>=item.price;
              const isEquip=!!item.slot;
              const rarC=item.rar?RARITY[item.rar].color:"#c8a96e";
              return(
                <div key={item.uid||i} style={{background:"rgba(12,10,6,.95)",border:`1px solid ${isEquip?rarC+"30":"#c8a96e20"}`,borderRadius:3,padding:10,marginBottom:7,animation:item.rar==="legendary"?"lgP 2s infinite":"none"}}>
                  <div style={{display:"flex",gap:8,alignItems:"center"}}>
                    <span style={{fontSize:20}}>{item.icon||"⚔️"}</span>
                    <div style={{flex:1}}>
                      <div style={{display:"flex",alignItems:"center",gap:5,marginBottom:3}}>
                        <span style={{fontSize:10,color:rarC,fontWeight:700}}>{item.name}</span>
                        {item.rar&&<RT r={item.rar}/>}
                      </div>
                      {isEquip&&(
                        <div style={{display:"flex",gap:6,fontSize:9,marginBottom:2}}>
                          {[["ATK",item.atk,"#ff8060"],["DEF",item.def,"#4080ff"],["SPD",item.spd,"#40c880"]].map(([l,v,c])=>v!==0&&<span key={l} style={{color:c}}>{l}<b>{v>0?"+":""}{v}</b></span>)}
                        </div>
                      )}
                      {item.fx&&<div style={{fontSize:7,color:"#ffc040",marginBottom:2}}>{item.fx.label}</div>}
                      {item.desc&&<div style={{fontSize:7,color:"#80aa80"}}>{item.desc}</div>}
                    </div>
                    <div style={{textAlign:"right",minWidth:60}}>
                      <div style={{fontSize:11,color:"#ffc040",fontWeight:700,marginBottom:4}}>💰{item.price}G</div>
                      <button onClick={()=>buyItem(item)} disabled={!canBuy} style={{background:canBuy?"rgba(200,169,110,.12)":"rgba(60,40,20,.3)",border:`1px solid ${canBuy?"#c8a96e40":"#7a6040"}`,color:canBuy?"#c8a96e":"#7a6040",padding:"4px 10px",cursor:canBuy?"pointer":"not-allowed",fontSize:8,fontFamily:"inherit",borderRadius:2,whiteSpace:"nowrap"}}>
                        {canBuy?"購入":"G不足"}
                      </button>
                    </div>
                  </div>
                </div>
              );
            })}

            <div style={{marginTop:8,padding:10,background:"rgba(10,8,6,.5)",border:"1px solid #1a1808",borderRadius:2,fontSize:7,color:"#706840",lineHeight:1.8}}>
              💡 装備はダンジョンドロップ＆ショップ購入で入手<br/>
              💡 ステータスブーストは永続効果<br/>
              💡 ショップは更新するたびにラインナップが変わる
            </div>
          </div>
        )}

        {/* SPELLS */}
        {scene==="town"&&tab==="spells"&&(
          <div style={{padding:12}}>
            <div style={{fontSize:8,color:"#c8a870",marginBottom:6}}>── 習得魔法 ({spells.length}/{SPELLS.length}) ──</div>
            {/* MP bar */}
            <div style={{marginBottom:10}}>
              <div style={{display:"flex",justifyContent:"space-between",fontSize:7,marginBottom:3}}>
                <span style={{color:"#8080a0"}}>MP</span>
                <span style={{color:mp>=20?"#7070ff":mp>0?"#ffb040":"#ff5040",fontWeight:700}}>{mp}/{maxMp}</span>
              </div>
              <div style={{height:4,background:"#0a0806",borderRadius:2,overflow:"hidden"}}>
                <div style={{height:"100%",borderRadius:2,width:`${mp/maxMp*100}%`,background:`linear-gradient(90deg,#4040c080,${mp>=20?"#7070ff":mp>0?"#ffb040":"#ff5040"})`,transition:"width .4s"}}/>
              </div>
              <div style={{fontSize:7,color:"#8080a0",marginTop:4}}>ヒール系HP≤30%・シールドHP≤50%で自動発動</div>
            </div>
            {SPELLS.map(s=>{
              const learned=spells.find(x=>x.id===s.id);
              const canCast=learned&&mp>=s.mp;
              const mpInsuf=learned&&mp<s.mp;
              return(
                <div key={s.id} style={{
                  background:canCast?"rgba(160,96,255,.06)":learned?"rgba(8,6,4,.6)":"rgba(8,6,4,.5)",
                  border:`1px solid ${canCast?"#c060ff22":learned?"#c060ff10":"#181208"}`,
                  borderRadius:2,padding:9,marginBottom:5,
                  opacity:learned?(canCast?1:.5):.4,
                }}>
                  <div style={{display:"flex",alignItems:"center",gap:7}}>
                    <span style={{fontSize:20,filter:canCast?"none":"grayscale(80%)"}}>{s.icon}</span>
                    <div style={{flex:1}}>
                      <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:2}}>
                        <span style={{fontSize:10,color:canCast?"#c080ff":learned?"#806090":"#c8a870",fontWeight:700}}>{s.name}</span>
                        <span style={{fontSize:7,color:canCast?"#7070ff":mpInsuf?"#ff5040":"#505070",border:`1px solid ${canCast?"#7070ff40":mpInsuf?"#ff504040":"#50507040"}`,padding:"1px 4px"}}>MP{s.mp}</span>
                        <span style={{fontSize:7,color:learned?"#40c880":"#706840"}}>{learned?"✓習得":"Lv."+s.lv}</span>
                        {mpInsuf&&<span style={{fontSize:7,color:"#ff5040"}}>MP不足</span>}
                      </div>
                      <div style={{fontSize:7,color:"#9a8aaa"}}>{s.desc}</div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {/* PASSIVES */}
        {scene==="town"&&tab==="passives"&&(
          <div style={{padding:12}}>
            <div style={{fontSize:8,color:"#c8a870",marginBottom:6}}>── パッシブスキル ({passives.length}/{PASSIVES.length}) ──</div>
            <div style={{fontSize:7,color:"#8080a0",marginBottom:10}}>レベルアップで自動解放・バトル中常時有効</div>
            {PASSIVES.map(p=>{const l=passives.find(x=>x.id===p.id);return(
              <div key={p.id} style={{background:l?"rgba(96,192,255,.06)":"rgba(8,6,4,.5)",border:`1px solid ${l?"#60c0ff22":"#181208"}`,borderRadius:2,padding:9,marginBottom:5,opacity:l?1:.45,animation:l?"sP 3s infinite":"none"}}>
                <div style={{display:"flex",alignItems:"center",gap:7}}>
                  <span style={{fontSize:20}}>{p.icon}</span>
                  <div style={{flex:1}}>
                    <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:2}}><span style={{fontSize:10,color:l?"#60c0ff":"#c8a870",fontWeight:700}}>{p.name}</span><span style={{fontSize:7,color:l?"#40c880":"#706840"}}>{l?"✓解放":"Lv."+p.lv+"で解放"}</span></div>
                    <div style={{fontSize:7,color:"#8aaaaa"}}>{p.desc}</div>
                  </div>
                </div>
              </div>
            );})}
          </div>
        )}

        {/* INVENTORY */}
        {scene==="town"&&tab==="inventory"&&(
          <div style={{padding:12}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
              <div style={{fontSize:8,color:"#c8a870"}}>所持品 ({inv.length}個)</div>
              <div style={{display:"flex",gap:5}}>
                <button onClick={autoEquip} style={{background:"rgba(200,169,110,.07)",border:"1px solid #c8a96e25",color:"#c8a96e",padding:"3px 8px",cursor:"pointer",fontSize:7,fontFamily:"inherit",borderRadius:2}}>⚡AUTO装備</button>
                <button onClick={()=>{const g=autoSell("common");showToast(g>0?`💰 コモン売却 +${g}G`:"売れるコモンなし");}} style={{background:"rgba(255,160,64,.07)",border:"1px solid #ffa04020",color:"#ffa040",padding:"3px 8px",cursor:"pointer",fontSize:7,fontFamily:"inherit",borderRadius:2}}>コモン売却</button>
                <button onClick={()=>{const g=autoSell("uncommon");showToast(g>0?`💰 ～アンコモン売却 +${g}G`:"売れるアイテムなし");}} style={{background:"rgba(255,160,64,.07)",border:"1px solid #ffa04020",color:"#ffa040",padding:"3px 8px",cursor:"pointer",fontSize:7,fontFamily:"inherit",borderRadius:2}}>～アンコモン売却</button>
              </div>
            </div>
            {!inv.length&&<div style={{fontSize:8,color:"#a08050",textAlign:"center",padding:20}}>アイテムがない。</div>}
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6}}>
              {inv.map((item,i)=>{
                const sellP=item.sell||RARITY[item.rar||"common"]?.sell||5;
                return(
                  <div key={item.uid||i} style={{background:"#0a0806",border:`1px solid ${RARITY[item.rar||"common"].color}22`,borderRadius:2,padding:8,animation:item.rar==="legendary"?"lgP 2s infinite":"none"}}>
                    <div style={{fontSize:16,marginBottom:2}}>{item.icon||"⚔️"}</div>
                    <div style={{fontSize:8,color:RARITY[item.rar||"common"].color,marginBottom:2}}>{item.name}</div>
                    <RT r={item.rar||"common"}/>
                    {item.slot&&<div style={{fontSize:7,color:"#7a8a60",marginTop:2}}>{[["ATK",item.atk],["DEF",item.def],["SPD",item.spd]].filter(([,v])=>v!==0).map(([l,v])=>`${l}${v>0?"+":""}${v}`).join(" ")}</div>}
                    {item.fx&&<div style={{fontSize:6,color:"#ffc040",marginTop:1}}>{item.fx.label}</div>}
                    <button onClick={()=>sellItem(item)} style={{width:"100%",marginTop:5,background:"rgba(255,160,64,.07)",border:"1px solid #ffa04018",color:"#ffa040",padding:"3px",cursor:"pointer",fontSize:7,fontFamily:"inherit",borderRadius:2}}>💰 {sellP}Gで売る</button>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* EXPLORE */}
        {scene==="explore"&&(
          <div style={{display:"flex",flexDirection:"column",height:"calc(100vh - 155px)"}}>
            <div style={{padding:"7px 14px",background:"#0a0806",borderBottom:"1px solid #2a2010",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
              <div><div style={{fontSize:10,color:"#e8d090",fontWeight:700}}>{dungeon?.icon}{dungeon?.name}</div><div style={{fontSize:7,color:"#c8a870"}}>{floor}F/{totalFloors}F</div></div>
              <div style={{textAlign:"right"}}>
                <div style={{fontSize:7,color:hpC}}>HP {hp}/{mxhp}</div><Bar v={hp} max={mxhp} c={hpC} h={3}/>
                <div style={{fontSize:7,color:"#9090d0",marginTop:1}}>MP {mp}/{maxMp}</div><Bar v={mp} max={maxMp} c="#7070ff" h={2}/>
                {combo>=3&&<div style={{fontSize:7,color:"#ffa040",marginTop:1}}>🔥 コンボ×{combo}</div>}
              </div>
            </div>
            <div style={{display:"flex",padding:"4px 14px",gap:3}}>
              {Array.from({length:totalFloors}).map((_,i)=>(<div key={i} style={{flex:1,height:3,borderRadius:2,background:i<floor?"#c8a96e":i===floor-1?"#ffc040":"#1a1808",transition:"background .3s"}}/>))}
            </div>
            <div ref={logRef} style={{flex:1,overflowY:"auto",padding:"4px 14px"}}>
              {log.map(l=>(<div key={l.id} style={{fontSize:10,lineHeight:1.8,color:l.c,animation:"fi .2s ease",whiteSpace:"pre-wrap"}}>{l.text}</div>))}
              {running&&<div style={{fontSize:9,color:"#c8a870",marginTop:3}}>▌</div>}
            </div>
          </div>
        )}

        {/* MEMOIR replay */}
        {memoirFloor&&SE[memoirFloor]&&(
          <StoryScreen floorId={memoirFloor} onNext={()=>setMemoirFloor(null)} isMemoir/>
        )}

        {/* MEMOIR 回想 */}
        {scene==="town"&&tab==="memoir"&&(
          <div style={{padding:12}}>
            <div style={{fontSize:10,color:"#c8a870",marginBottom:4,fontWeight:700,letterSpacing:".1em"}}>
              📖 回想録
            </div>
            <div style={{fontSize:8,color:"#6a5a3a",marginBottom:12}}>
              クリアした階層のストーリーをもう一度見ることができます
            </div>
            {DUNGEONS.filter(d=>viewedStories.has(d.id)).length===0&&(
              <div style={{fontSize:9,color:"#3a2a0a",textAlign:"center",padding:20}}>
                まだクリアした階層がありません
              </div>
            )}
            {[1,2,3].map(phase=>{
              const phaseLabel=["第1部 ── 違和感とミリア","第2部 ── 国家の実験とイデア","第3部 ── 魔王と解放"][phase-1];
              const floors=DUNGEONS.filter(d=>d.phase===phase&&viewedStories.has(d.id));
              if(!floors.length) return null;
              return(
                <div key={phase} style={{marginBottom:14}}>
                  <div style={{
                    fontSize:8,color:phase===1?"#40c0b0":phase===2?"#8060ff":"#ff8060",
                    letterSpacing:".12em",marginBottom:8,borderBottom:"1px solid #1a1808",paddingBottom:4,
                  }}>── {phaseLabel} ──</div>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:5}}>
                    {floors.map(d=>{
                      const ev=SE[d.id];
                      if(!ev) return null;
                      const isMajor=ev.major;
                      return(
                        <button key={d.id} onClick={()=>setMemoirFloor(d.id)} style={{
                          background:isMajor?"rgba(255,128,96,.06)":"rgba(200,169,110,.04)",
                          border:`1px solid ${isMajor?"#ff806025":"#c8a96e18"}`,
                          borderRadius:2,padding:"7px 8px",cursor:"pointer",
                          fontFamily:"inherit",textAlign:"left",
                        }}>
                          <div style={{fontSize:8,color:"#6a5a3a",marginBottom:2}}>
                            {d.icon} 第{d.id}層
                            {isMajor&&<span style={{color:"#ff8060",marginLeft:4}}>★</span>}
                          </div>
                          <div style={{fontSize:9,color:isMajor?"#ff9070":"#c8a870",lineHeight:1.4}}>
                            {ev.t.replace("【大】","").replace("【大イベント】","")}
                          </div>
                        </button>
                      );
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {/* STORY - only render when SE data exists for this floor */}
        {scene==="story"&&storyFloor&&SE[storyFloor]&&(
          <StoryScreen floorId={storyFloor} onNext={storyDone}/>
        )}

        {/* RESULT */}
        {scene==="result"&&(
          <ResultOverlay
            hp={hp} rank={rank}
            newSpells={newSpells} newPassives={newPassives}
            legDrop={legDrop}
            drops={lastResult?.drops||[]}
            dungeonName={lastResult?.dungeonName||""}
            dungeonIcon={lastResult?.dungeonIcon||""}
            gold={gold} lv={lv}
            onDone={collectLoot}
          />
        )}
      </div>

      {scene==="town"&&st<MAX_ST&&(
        <div style={{borderTop:"1px solid #1a1808",padding:"5px 14px",background:"rgba(6,8,12,.99)",display:"flex",alignItems:"center",justifyContent:"space-between",fontSize:7}}>
          <span style={{color:"#a08050"}}>全回復まで{MAX_ST-st}分</span>
          <a href={PUMP_URL} target="_blank" rel="noopener noreferrer" style={{textDecoration:"none",background:"rgba(200,169,110,.06)",border:"1px solid #c8a96e18",color:"#c8a96e",padding:"3px 8px",borderRadius:2,fontSize:7}}>⚡{RESTORE}$KOUNO で全回復</a>
        </div>
      )}
    </div>
  );
}
